{{#switch:{{{form|}}}
 |editnotice = {{editnotice
  |id    = {{{id|}}}
  |image = [[Image:Ambox warning yellow.svg|40x40px|alt=|link=]]
  |text  = {{Intricate template/text}}
  |expiry= {{{expiry|}}}
 }}
 |#default = {{ombox
  |type  = style
  |image = [[Image:Ambox warning yellow.svg|40x40px|alt=|link=]]
  |text  = {{Intricate template/text}}
 }}
}}<includeonly>{{#ifeq: {{PAGENAME}} | {{BASEPAGENAME}} | {{template other| [[Category:Intricate templates]] }} }}</includeonly><noinclude>
{{Documentation}}
<!-- Add categories to the /doc subpage; interwikis go to Wikidata, thank you! -->
</noinclude>

